--- /dev/null
+++ b/src/checkout.ts
@@ -0,0 +1,18 @@
+type Cart = { subtotal: number; coupon?: string };
+
+export function checkout(cart: Cart) {
+  const total = helper(cart);
+  return { total };
+}
+
+function helper(cart: Cart) {
+  if (cart.coupon === "SAVE10") {
+    return cart.subtotal - 10;
+  }
+  return cart.subtotal;
+}
